import stanza

# 1. 스탠퍼드 영어(en) 모델 다운로드 (수형도 분석기인 'constituency' 포함)
# (최초 실행 시 언어 데이터를 다운받느라 1~2분 정도 걸릴 수 있습니다)
print("스탠퍼드 언어 모델 다운로드 중...")
stanza.download('en', processors='tokenize,pos,constituency')

# 2. 분석 파이프라인 만들기 (이제 텍스트를 넣을 준비가 되었습니다!)
nlp = stanza.Pipeline('en', processors='tokenize,pos,constituency')

# 3. 분석할 문장 준비 (제퍼슨과 해밀턴의 대표 문장)
jefferson_text = "We hold these truths to be self-evident, that all men are created equal."
hamilton_text = "A dangerous ambition more often lurks behind the specious mask of zeal for the rights of the people."

# 4. 파이썬이 문장 분석 실행
print("\n문장 구조 분석 중...\n")
doc_j = nlp(jefferson_text)
doc_h = nlp(hamilton_text)

# 5. 결과 출력 (우리가 그토록 원하던 대괄호 수형도 형태!)
print("====================================")
print("[제퍼슨의 수형도 데이터]")
for sentence in doc_j.sentences:
    print(sentence.constituency)

print("\n====================================")
print("[해밀턴의 수형도 데이터]")
for sentence in doc_h.sentences:
    print(sentence.constituency)

