import nltk
from nltk.tree import Tree
from IPython.display import display

# 스탠퍼드가 뽑아낸 제퍼슨의 괄호 데이터를 그림으로 그리기
tree_string_j = str(doc_j.sentences[0].constituency)
tree_j = Tree.fromstring(tree_string_j)
print("[제퍼슨 수형도 시각화]")
display(tree_j)

print("\n" + "="*50 + "\n")

# 스탠퍼드가 뽑아낸 해밀턴의 괄호 데이터를 그림으로 그리기
tree_string_h = str(doc_h.sentences[0].constituency)
tree_h = Tree.fromstring(tree_string_h)
print("[해밀턴 수형도 시각화]")
display(tree_h)

# 제퍼슨 수형도의 최대 깊이 계산
depth_j = tree_j.height()
print(f"제퍼슨 문장의 최대 노드 깊이: {depth_j}층")

# 해밀턴 수형도의 최대 깊이 계산
depth_h = tree_h.height()
print(f"해밀턴 문장의 최대 노드 깊이: {depth_h}층")

import stanza

# 1. 이번에는 수형도(constituency)가 아니라 '의존성 구문 분석(depparse)' 파이프라인을 켯니다!
# 필요한 모든 모델을 다운로드합니다.
print("필요한 모든 Stanza 모델 다운로드 중 (tokenize, pos, lemma, depparse)...")
stanza.download(lang="en", processors='tokenize,pos,lemma,depparse')

nlp_dep = stanza.Pipeline('en', processors='tokenize,pos,lemma,depparse', download_method=None) # Models are already downloaded

# 2. 분석할 문장 (이미 입력해둔 제퍼슨, 해밀턴 문장)
doc_j_dep = nlp_dep(jefferson_text)
doc_h_dep = nlp_dep(hamilton_text)

# 3. 의존성 거리(Dependency Distance)를 계산하는 파이썬 함수 만들기
def calc_avg_dependency_distance(doc):
    total_distance = 0
    relations_count = 0

    for sentence in doc.sentences:
        for word in sentence.words:
            if word.head != 0: # ROOT(뿌리)로 향하는 연결은 제외하고 실제 단어 간의 거리만 계산
                distance = abs(word.id - word.head) # |현재 단어 위치 - 꾸며주는 단어 위치|
                total_distance += distance
                relations_count += 1

    return total_distance / relations_count if relations_count > 0 else 0

# 4. 결과 출력!
dist_j = calc_avg_dependency_distance(doc_j_dep)
dist_h = calc_avg_dependency_distance(doc_h_dep)

print(f"제퍼슨 문장의 평균 의존성 거리: {dist_j:.2f}")
print(f"해밀턴 문장의 평균 의존성 거리: {dist_h:.2f}")

