import stanza

# 1. 이번에는 수형도(constituency)가 아니라 '의존성 구문 분석(depparse)' 파이프라인을 켯니다!
# 필요한 모든 모델을 다운로드합니다.
print("필요한 모든 Stanza 모델 다운로드 중 (tokenize, pos, lemma, depparse)...")
stanza.download(lang="en", processors='tokenize,pos,lemma,depparse')

nlp_dep = stanza.Pipeline('en', processors='tokenize,pos,lemma,depparse', download_method=None) # Models are already downloaded

# 2. 분석할 문장 (이미 입력해둔 제퍼슨, 해밀턴 문장)
doc_j_dep = nlp_dep(jefferson_text)
doc_h_dep = nlp_dep(hamilton_text)

# 3. 의존성 거리(Dependency Distance)를 계산하는 파이썬 함수 만들기
def calc_avg_dependency_distance(doc):
    total_distance = 0
    relations_count = 0

    for sentence in doc.sentences:
        for word in sentence.words:
            if word.head != 0: # ROOT(뿌리)로 향하는 연결은 제외하고 실제 단어 간의 거리만 계산
                distance = abs(word.id - word.head) # |현재 단어 위치 - 꾸며주는 단어 위치|
                total_distance += distance
                relations_count += 1

    return total_distance / relations_count if relations_count > 0 else 0

# 4. 결과 출력!
