import minicons

from minicons import scorer

# GPT-2로 의외성(서프라이절) 측정
model = scorer.IncrementalLMScorer('gpt2', 'cpu')

# 6쌍 문장
pairs = {
 "1 사법독립": {
   "J":  "He has obstructed the Administration of Justice, by refusing his Assent to Laws for establishing Judiciary powers." ,
   "H":  "The complete independence of the courts of justice is peculiarly essential in a limited Constitution." },
 "2 군사/민간": {
   "J": "He has affected to render the military independent of, and superior to, the civil power.",
   "H": "The continual necessity for their services enhances the importance of the soldier, and proportionably degrades the condition of the citizen."
},
 "3 폭정/선동가": {
   "J":  "A Prince, whose character is thus marked by every act which may define a Tyrant, is unfit to be the ruler of a free people." ,
   "H": "History will teach us that the former has been found a much more certain road to the introduction of despotism than the latter."
    },
 "4 행정/대의기구": {
   "J": "He has dissolved Representative Houses repeatedly, for opposing, with manly firmness, his invasions on the rights of the people." ,
   "H": "There is an idea, which is not without its advocates, that a vigorous Executive is inconsistent with the genius of republican government."},
 "5 연방안전": {
   "J": "That these United Colonies are, and of Right ought to be Free and Independent States.",
   "H": "A firm Union will be of the utmost moment to the peace and liberty of the States, as a barrier against domestic faction and insurrection."},
 "6 정부목적": {
   "J": "It is their right, it is their duty, to throw off such Government, and to provide new Guards for their future security.",
   "H": "Because the passions of men will not conform to the dictates of reason and justice, without constraint."},
}

# 각 문장의 평균 서프라이절 계산 (bits 단위)
print(f"{'쌍':<14}{'저자':<4}{'평균 서프라이절':>15}")
print("-" * 35)
for name, p in pairs.items():
    for author in ("J", "H"):
        scores = model.token_score(p[author], surprisal=True, base_two=True)[0]
        # 첫 토큰(0.0)은 빼고 평균
        vals = [s for w, s in scores[1:]]
        avg = sum(vals) / len(vals)
        print(f"{name:<14}{author:<4}{avg:>15.2f}")
    print("-" * 35)

